CREATE TABLE IF NOT EXISTS indicators ( stock_id TEXT NOT NULL, date TEXT NOT NULL, ret_1d REAL, ret_5d REAL, ret_20d REAL, ma5 REAL, ma10 REAL, ma20 REAL, ma5_bias REAL, ma20_bias REAL, volume_ratio_5d REAL, volatility_20d REAL, intraday_range_pct REAL, rsi_14 REAL, k_value REAL, d_value REAL, macd REAL, macd_signal REAL, macd_hist REAL, bollinger_upper REAL, bollinger_middle REAL, bollinger_lower REAL, foreign_net_ratio REAL, trust_net_ratio REAL, dealer_net_ratio REAL, institutional_net_ratio REAL, foreign_holding_change_5d REAL, margin_balance_change_5d REAL, short_balance_change_5d REAL, mainforce_net_ratio REAL, revenue_yoy_ratio REAL, revenue_mom_ratio REAL, eps_change_value REAL, twii_return_20d REAL, bullish_signal_count INTEGER, bearish_signal_count INTEGER, long_short_signal_score INTEGER, long_short_signal_ratio REAL, created_at TEXT, updated_at TEXT, PRIMARY KEY (stock_id, date) );
